{"file_path": "/project/test_future_issue.kt", "content": "import kotlinx.coroutines.*
import kotlinx.coroutines.future.*
import java.util.concurrent.CompletableFuture

fun main() {
    println("Test 1: future with error, then cancel")
    try {
        val future = GlobalScope.future {
            error("foo")
        }
        future.cancel(true)
        Thread.sleep(100)
        println("Test 1 passed - no exception thrown")
    } catch (e: Exception) {
        println("Test 1 FAILED - exception thrown: ${e.message}")
    }

    println("\nTest 2: async with error, then cancel")
    try {
        val deferred = GlobalScope.async {
            error("bar")
        }
        deferred.cancel()
        Thread.sleep(100)
        println("Test 2 passed - no exception thrown")
    } catch (e: Exception) {
        println("Test 2 FAILED - exception thrown: ${e.message}")
    }

    println("\nTest 3: future with error, await")
    try {
        runBlocking {
            val future = GlobalScope.future {
                error("baz")
            }
            future.await()
        }
        println("Test 3 FAILED - should have thrown exception")
    } catch (e: Exception) {
        println("Test 3 passed - exception thrown as expected: ${e.message}")
    }
}"}

